mapper.select:
SELECT a.box_cd, a.box_nm, a.box_count, a.box_price, a.deposit, a.high_num, a.row_num, a.start_num, a.end_num, (SELECT COUNT(BOX_NUM) FROM BOX_info WHERE BOX_CD=a.BOX_CD AND BOX_FLAG = 'Y') use_num, (SELECT COUNT(BOX_NUM) FROM BOX_info WHERE BOX_CD=a.BOX_CD AND BOX_FLAG = 'N') req_num FROM BOX_MST a WHERE ISUSE = 'Y'
AND a.box_nm LIKE '%' #{searchKeyword} '%'
ORDER BY BOX_CD ASC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT a.box_cd, a.box_nm, a.box_count, a.box_price, a.deposit, a.high_num, a.row_num, a.start_num, a.end_num 
FROM BOX_MST a
WHERE a.BOX_CD = #{boxCd}

mapper.delete:
   		UPDATE BOX_MST
   		SET ISUSE = 'N' 
		WHERE BOX_CD = #{boxCd}

mapper.select:
SELECT BOX_CD, BOX_NUM, a.USER_ID, b.USER_NM, BOX_FLAG, UPD_DT, UPD_ID, RENT_SEQ 
FROM box_info a
LEFT OUTER JOIN MEMBER_MST b ON a.USER_ID = b.USER_ID
WHERE a.BOX_CD = #{boxCd}
AND a.box_num = #{boxNum}

mapper.insert:
INSERT INTO box_info (
	BOX_CD, BOX_NUM, BOX_FLAG, RENT_MEMO, upd_dt, upd_id
) VALUES (
	#{boxCd}, #{boxNum}, #{boxFlag}, #{rentMemo}, now(), #{updId}
)

mapper.select:
		SELECT a.box_cd, a.box_num, a.user_id, a.box_flag, a.rent_seq, 
       			b.rent_start, b.RENT_END, b.DEPOSIT, b.DEPOSIT_YN, b.EXTEND_YN, b.KEY_YN, b.RENT_TYPE, b.PAY_GUBUN,
      	 		case when b.rent_memo IS NULL then a.RENT_MEMO ELSE a.rent_memo END rent_memo, b.ORDER_ID
		FROM box_info a, box_rent b
		WHERE a.BOX_CD= b.BOX_CD
		AND a.BOX_NUM = b.BOX_NUM
		AND a.RENT_SEQ = b.RENT_SEQ
		and a.box_cd = #{boxCd}
		and a.box_num = #{boxNum}
		and a.rent_seq = #{rentSeq}

SELECT user_id, rent_start, RENT_END, DEPOSIT, DEPOSIT_YN, EXTEND_YN, KEY_YN, RENT_TYPE, PAY_GUBUN, rent_memo, ORDER_ID
FROM box_rent
WHERE box_cd = #{boxCd}
and box_num = #{boxNum}
order by rent_seq
